grate","expression":{"type":"Applicability","mode":"query","value":"hey_how_can_i_help_you_=How to Migrate"},"id":"6e38d696c2c54814a2900f70b5e7901d","name":"How to migrate","expert_mode":false},{"type":"Branch","label":"About TraceNow","expression":{"type":"Applicability","mode":"query","value":"hey_how_can_i_help_you_=About TraceNow"},"id":"405b059532834907bea5854701a56734","name":"About TraceNow","expert_mode":false}],"id":"5791dba158ab4b82af44f9353f3fd803","goal_id":"primary","expert_mode":false},{"type":"InputPrompt","variable_id":"58baa69022bb4e7bb6af2f1d62c95c4b","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Enter URL of source Instance", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"request_feedback":true,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"2375ac78b4074ce184177e7edddadb54","name":"URL","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"InputPrompt","variable_id":"c97b18dc1cce4b12a46b6cbb2ee7cf91","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Enter Password of source Instance", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"request_feedback":true,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"779937f547e54d6d8966ccd1d5a11883","name":"Password","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"InputPrompt","variable_id":"7cb36de39edc4ca695b9024030f4731c","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Enter UserName of source Instance.", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"request_feedback":true,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"209fbbe1b11f4f2fb1be2c5966cd6683","name":"UserName","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"ScriptedAction","script":"(function execute() {
 try {
 var conn = new GlideRecord('x_sysus_tracenow_connection');
 conn.addQuery('sys_created_by', gs.getUserName());
 conn.addQuery('state', true); // the active connection
 conn.orderByDesc('sys_updated_on');
 conn.setLimit(1);
 conn.query();

 if (!conn.next()) { vaVars.connection_status = 'NO_ACTIVE_CONNECTION'; return; }

 vaVars.url = conn.getValue('url');
 vaVars.username = conn.getValue('username');
 vaVars.password = conn.getValue('password'); // see caveat below

 var r = new sn_ws.RESTMessageV2();
 r.setHttpMethod('get');
 r.setEndpoint(vaVars.url + '/api/now/table/sys_user?sysparm_limit=1&sysparm_fields=sys_id');
 r.setBasicAuth(vaVars.username, vaVars.password);
 r.setRequestHeader('Accept', 'application/json');
 vaInputs.connection_status = String(r.execute().getStatusCode());
 } catch (e) {
 vaInputs.connection_status = 'ERROR: ' + e.message;
 }
})()","id":"c0b739792afd46ba842d1428705e8a52","name":"Validate connection","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("Connection status: {0}", vaContext.getRequesterLang(), [vaInputs.connection_status])"}],"request_feedback":true,"isCollapsible":true,"id":"8e8b883f00794a83993f1723a19d7a25","name":"Connection status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"InputPrompt","variable_id":"4cc76ce0d1714b549fdce6c10e3190c8","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Set by NLU", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":false},"request_feedback":false,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"6120de8b4f604ad4a8f76f4674581476","name":"connection_status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"(function() { return (function() { return false; })()})()"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"Decision","name":"Decision","branches":[{"type":"Branch","label":"Connected","expression":{"type":"Applicability","mode":"query","value":"connection_status=200"},"id":"54c5247ffe9248fba1b68f6319dd68c8","name":"Connected","expert_mode":false},{"type":"Branch","label":"Not Connected","expression":{"type":"Applicability","mode":"query","value":"connection_status!=200"},"id":"a4432ba96121409cb116d23c8e7c3d3f","name":"Not Connected","expert_mode":false}],"id":"a867047d80b14f07b4be4af702c11013","goal_id":"primary","expert_mode":false},{"type":"InputPrompt","variable_id":"f5e97c7b6d94497da1a900e863d168b0","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Enter Table Name.", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"request_feedback":true,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"767fcb4a9a99424b9c02f2db1608337c","name":"Table","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"InputPrompt","variable_id":"7a722db6f8d147b3befeb7ad9e63ce7b","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Set by NLU", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":false},"request_feedback":false,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"ff1ef4615af042719b07802ff8808411","name":"table_status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"(function() { return (function() { return false; })()})()"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"ScriptedAction","script":"(function execute() {

 try {

 var table = String(vaInputs.table || '').trim();

 if (!table) {
 vaInputs.table_status = 'no_table';
 return;
 }

 var gr = new GlideRecord('sys_db_object');
 gr.addQuery('name', table);
 gr.query();

 if (gr.next()) {
 vaInputs.table_status = 'found';
 } else {
 vaInputs.table_status = 'not_found';
 }

 } catch (e) {

 vaInputs.table_status = 'error';

 }

})();","id":"b6c3d3541bb942d78c13cbada4b66048","name":"table_status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("Table : {0}", vaContext.getRequesterLang(), [vaInputs.table_status])"}],"request_feedback":true,"isCollapsible":true,"id":"36c295e4c59c4c0695efd4bf85bb5ec0","name":"table_status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"Decision","name":"Decision","branches":[{"type":"Branch","label":"not found","expression":{"type":"Applicability","mode":"query","value":"table_status!=found"},"id":"e31409cd5f8e44178ce03d9bb5d01c45","name":"not found","expert_mode":false},{"type":"Branch","label":"found","expression":{"type":"Applicability","mode":"query","value":"table_status=found"},"id":"030098c9110d49c48ca6517e005628f0","name":"found","expert_mode":false}],"id":"eee6d842d9a349c7bec0f7acd42f0789","goal_id":"primary","expert_mode":false},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("va:topic:fa3b18b3939dc3900af5f4e9b903d6f8:node:e65e52f72ab441b2b042101880a725d2:field:0", vaContext.getRequesterLang())"}],"request_feedback":true,"isCollapsible":true,"id":"e65e52f72ab441b2b042101880a725d2","name":"Let's Start Again.","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("va:topic:fa3b18b3939dc3900af5f4e9b903d6f8:node:cbf6d20b210e4122994f8be540c22718:field:0", vaContext.getRequesterLang())"}],"request_feedback":true,"isCollapsible":true,"id":"cbf6d20b210e4122994f8be540c22718","name":"Let's Start Again.","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"InputPrompt","variable_id":"f1ce34a0ab3b4652a26680a398fa58a0","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Enter Sys ID of the Record.", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"request_feedback":true,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"926872d650f945e9b0d6bd6cdc0b2af9","name":"SysID ","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"InputPrompt","variable_id":"dbb9535278d64b078c07034117b2e9b0","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Set by NLU", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":false},"request_feedback":false,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"0c170dc6eb494e31882d3caf7450c8d9","name":"record_status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"(function() { return (function() { return false; })()})()"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"ScriptedAction","script":"(function execute() {
 try {
 var url = String(vaInputs.url || '').trim().replace(/\/+$/, '');
 var user = String(vaInputs.username || '').trim();
 var table = String(vaInputs.table || '').trim().toLowerCase();
 var sysId = String(vaInputs.sysid_ || '').trim().toLowerCase();

 if (!url || !user || !table || !sysId) {
 vaInputs.record_status = 'missing_input';
 return;
 }
 if (!/^[0-9a-f]{32}$/.test(sysId)) {
 vaInputs.record_status = 'bad_sys_id';
 return;
 }

 /* Password: now that the chat input is UNENCRYPTED, use it directly.
 Fall back to the system property only if chat gave nothing usable
 (empty, or the "$s$…" cipher if encryption is ever re-enabled). */
 var pass = String(vaInputs.password || '');
 if (!pass || pass.indexOf('$s$') === 0) {
 pass = String(gs.getProperty('x_sysus_tracenow.dm.source_password') || '');
 }
 if (!pass || pass.indexOf('$s$') === 0) {
 vaInputs.record_status = 'no_password';
 return;
 }

 /* ---- SOURCE check (REST — other instance, needs auth) ---- */
 var rm = new sn_ws.RESTMessageV2();
 rm.setEndpoint(url + '/api/now/table/' + encodeURIComponent(table) +
 '/' + sysId + '?sysparm_fields=sys_id,number');
 rm.setHttpMethod('GET');
 rm.setBasicAuth(user, pass);
 rm.setRequestHeader('Accept', 'application/json');
 rm.setHttpTimeout(15000);

 var status = rm.execute().getStatusCode();
 gs.info('[RECORD CHECK] source status=' + status + ' for ' + table + '/' + sysId);

 if (status == 404) { vaInputs.record_status = 'not_found'; return; }
 if (status == 401) { vaInputs.record_status = 'auth_failed'; return; }
 if (status != 200) { vaInputs.record_status = 'error_' + status; return; }

 /* ---- TARGET check (GlideRecord — this instance, no auth, your style) ---- */
 var gr = new GlideRecord(table);
 if (gr.isValid() && gr.get(sysId)) {
 vaInputs.record_status = 'already_migrated';
 } else {
 vaInputs.record_status = 'found';
 }

 } catch (e) {
 gs.error('[RECORD CHECK] ' + e);
 vaInputs.record_status = 'error';
 }
})();","id":"7e566220cb5d4e43a0c78a3d066cc346","name":"record_status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("Record : {0}", vaContext.getRequesterLang(), [vaInputs.record_status])"}],"request_feedback":true,"isCollapsible":true,"id":"9161ec073a45448aa5c3b27ca72b6d47","name":"record_status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"Decision","name":"Decision","branches":[{"type":"Branch","label":"not found","expression":{"type":"Applicability","mode":"query","value":"record_status!=found"},"id":"f3dee442820e4c3abfadb70b7f52189e","name":"not found","expert_mode":false},{"type":"Branch","label":"found","expression":{"type":"Applicability","mode":"query","value":"record_status=found"},"id":"847f560b088b46c3ac41dc3c9c35558a","name":"found","expert_mode":false}],"id":"5ac00b37f1d248299c2b8c29da66fa42","goal_id":"primary","expert_mode":false},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("va:topic:fa3b18b3939dc3900af5f4e9b903d6f8:node:8cfb66cb48bf47ce86e48d38eb984558:field:0", vaContext.getRequesterLang())"}],"request_feedback":true,"isCollapsible":true,"id":"8cfb66cb48bf47ce86e48d38eb984558","name":"Let's Start Again.","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"ChoiceInputPrompt","expression_mode":"simple","metadataScript":"","cardName":"","cardFields":[],"id":"27a37296a74f472a9e682f6c44e4fff7","name":"Ready to migrate?","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"variable_id":"476cf45911f34177908c58cef9c53c5f","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Ready to migrate?", vaContext.getRequesterLang())"},"request_feedback":false,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"description":""},{"type":"Decision","name":"Decision","branches":[{"type":"Branch","label":"cancel","expression":{"type":"Applicability","mode":"query","value":"ready_to_migrate_=cancel"},"id":"97956af9d35543d6838f20848d2f59ae","name":"cancel","expert_mode":false},{"type":"Branch","label":"Migrate Now","expression":{"type":"Applicability","mode":"query","value":"ready_to_migrate_=Migrate Now"},"id":"f8cba08b99d2468188f9475d7079b401","name":"Migrate Now","expert_mode":false}],"id":"de7f975262e744f488808d47100ef147","goal_id":"primary","expert_mode":false},{"type":"InputPrompt","variable_id":"8bc69d46dfc344d0abf89e43ea0c2e9d","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Set by NLU", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":false},"request_feedback":false,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"ce53f3a0f50649b3a2683eee9116c92b","name":"migration_status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"(function() { return (function() { return false; })()})()"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"ScriptedAction","script":"(function execute() {
 try {
 var url = String(vaInputs.url || '').trim().replace(/\/+$/, '');
 var user = String(vaInputs.username || '').trim();
 var pass = String(vaInputs.password || '').trim();
 var table = String(vaInputs.table || '').trim().toLowerCase();
 var sysId = String(vaInputs.sysid_ || '').trim().toLowerCase();

 if (!url || !user || !pass || !table || !sysId) {
 vaInputs.migration_status = 'Missing input — need url, username, password, table, sys_id.';
 return;
 }
 if (!/^[0-9a-f]{32}$/.test(sysId)) {
 vaInputs.migration_status = '"' + sysId + '" is not a valid sys_id.';
 return;
 }

 var engine = new DM_MigrationCore();
 engine.SOURCE_URL = url;
 engine.SOURCE_USER = user;
 engine.SOURCE_PSWD = pass;
 engine.DEBUG = false; // keep false: logging slows the run and
 // every second counts against the timeout

 var startMs = new GlideDateTime().getNumericValue();
 var targetSysId = engine.migrateWithDependencies(table, sysId, 0);
 var secs = Math.round((new GlideDateTime().getNumericValue() - startMs) / 1000);
 var s = engine.stats || {};

 if (targetSysId) {
 /* pull the target number for a friendlier summary */
 var num = '';
 var tg = new GlideRecord(table);
 if (tg.get(targetSysId) && tg.isValidField('number')) num = tg.getValue('number');

 vaInputs.migration_status =
 '✅ Migration completed in ' + secs + 's.\n' +
 (num ? 'Record: ' + num + '\n' : '') +
 'Target sys_id: ' + targetSysId + '\n';
 } else {
 vaInputs.migration_status =
 '❌ Migration returned no target sys_id after ' + secs + 's — ' +
 'check the system log (Created = Today) for details.';
 }

 } catch (e) {
 var msg = (e && e.message) ? e.message : String(e);
 vaInputs.migration_status = '❌ Migration failed: ' + msg;
 gs.error('[VA migrate sync] ' + msg + ' | ' + ((e && e.stack) ? e.stack : ''));
