        "7e566220cb5d4e43a0c78a3d066cc346": {
          "id": "7e566220cb5d4e43a0c78a3d066cc346",
          "name": "record_status",
          "script": "(function execute() {\n    try {\n        var url   = String(vaInputs.url      || '').trim().replace(/\\/+$/, '');\n        var user  = String(vaInputs.username || '').trim();\n        var table = String(vaInputs.table    || '').trim().toLowerCase();\n        var sysId = String(vaInputs.sysid_   || '').trim().toLowerCase();\n\n        if (!url || !user || !table || !sysId) {\n            vaInputs.record_status = 'missing_input';\n            return;\n        }\n        if (!/^[0-9a-f]{32}$/.test(sysId)) {\n            vaInputs.record_status = 'bad_sys_id';\n            return;\n        }\n\n        /* Password: now that the chat input is UNENCRYPTED, use it directly.\n           Fall back to the system property only if chat gave nothing usable\n           (empty, or the \"$s$…\" cipher if encryption is ever re-enabled). */\n        var pass = String(vaInputs.password || '');\n        if (!pass || pass.indexOf('$s$') === 0) {\n            pass = String(gs.getProperty('x_sysus_tracenow.dm.source_password') || '');\n        }\n        if (!pass || pass.indexOf('$s$') === 0) {\n            vaInputs.record_status = 'no_password';\n            return;\n        }\n\n        /* ---- SOURCE check (REST — other instance, needs auth) ---- */\n        var rm = new sn_ws.RESTMessageV2();\n        rm.setEndpoint(url + '/api/now/table/' + encodeURIComponent(table) +\n                       '/' + sysId + '?sysparm_fields=sys_id,number');\n        rm.setHttpMethod('GET');\n        rm.setBasicAuth(user, pass);\n        rm.setRequestHeader('Accept', 'application/json');\n        rm.setHttpTimeout(15000);\n\n        var status = rm.execute().getStatusCode();\n        gs.info('[RECORD CHECK] source status=' + status + ' for ' + table + '/' + sysId);\n\n        if (status == 404)      { vaInputs.record_status = 'not_found';   return; }\n        if (status == 401)      { vaInputs.record_status = 'auth_failed'; return; }\n        if (status != 200)      { vaInputs.record_status = 'error_' + status; return; }\n\n        /* ---- TARGET check (GlideRecord — this instance, no auth, your style) ---- */\n        var gr = new GlideRecord(table);\n        if (gr.isValid() && gr.get(sysId)) {\n            vaInputs.record_status = 'already_migrated';\n        } else {\n            vaInputs.record_status = 'found';\n        }\n\n    } catch (e) {\n        gs.error('[RECORD CHECK] ' + e);\n        vaInputs.record_status = 'error';\n    }\n})();",
          "stepType": "ScriptAction",
          "applicability": {
            "value": "",
            "mode": "query"
          }
        },
