        "5d66ecbf4a564d558d420954f3c62637": {
          "id": "5d66ecbf4a564d558d420954f3c62637",
          "name": "migration_status",
          "script": "(function execute() {\n    try {\n        var url   = String(vaInputs.url      || '').trim().replace(/\\/+$/, '');\n        var user  = String(vaInputs.username || '').trim();\n        var pass  = String(vaInputs.password || '').trim();\n        var table = String(vaInputs.table    || '').trim().toLowerCase();\n        var sysId = String(vaInputs.sysid_   || '').trim().toLowerCase();\n\n        if (!url || !user || !pass || !table || !sysId) {\n            vaInputs.migration_status = 'Missing input — need url, username, password, table, sys_id.';\n            return;\n        }\n        if (!/^[0-9a-f]{32}$/.test(sysId)) {\n            vaInputs.migration_status = '\"' + sysId + '\" is not a valid sys_id.';\n            return;\n        }\n\n        var engine = new DM_MigrationCore();\n        engine.SOURCE_URL  = url;\n        engine.SOURCE_USER = user;\n        engine.SOURCE_PSWD = pass;\n        engine.DEBUG       = false;     // keep false: logging slows the run and\n                                        // every second counts against the timeout\n\n        var startMs     = new GlideDateTime().getNumericValue();\n        var targetSysId = engine.migrateWithDependencies(table, sysId, 0);\n        var secs        = Math.round((new GlideDateTime().getNumericValue() - startMs) / 1000);\n        var s           = engine.stats || {};\n\n        if (targetSysId) {\n            /* pull the target number for a friendlier summary */\n            var num = '';\n            var tg = new GlideRecord(table);\n            if (tg.get(targetSysId) && tg.isValidField('number')) num = tg.getValue('number');\n\n            vaInputs.migration_status =\n                '✅ Migration completed in ' + secs + 's.\\n' +\n                (num ? 'Record: ' + num + '\\n' : '') +\n                'Target sys_id: ' + targetSysId + '\\n';\n        } else {\n            vaInputs.migration_status =\n                '❌ Migration returned no target sys_id after ' + secs + 's — ' +\n                'check the system log (Created = Today) for details.';\n        }\n\n    } catch (e) {\n        var msg = (e && e.message) ? e.message : String(e);\n        vaInputs.migration_status = '❌ Migration failed: ' + msg;\n        gs.error('[VA migrate sync] ' + msg + ' | ' + ((e && e.stack) ? e.stack : ''));\n    }\n})();",
          "stepType": "ScriptAction",
          "applicability": {
            "value": "",
            "mode": "query"
          }
        },
